import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Dashboard() {
  const [productos, setProductos] = useState([]);
  const [nuevoProducto, setNuevoProducto] = useState({
    productoID: "",
    nombre: "",
    precio: "",
    stock: "",
  });
  const [editando, setEditando] = useState(false);

  const API_URL = "http://localhost:5000/api/productos";

  // 🔹 Obtener productos
  const obtenerProductos = async () => {
    try {
      const res = await axios.get(API_URL);
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  useEffect(() => {
    obtenerProductos();
  }, []);

  // 🔹 Manejar cambios en el formulario
  const handleChange = (e) => {
    setNuevoProducto({ ...nuevoProducto, [e.target.name]: e.target.value });
  };

  // 🔹 Agregar o actualizar producto
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editando) {
        await axios.put(`${API_URL}/${nuevoProducto.productoID}`, nuevoProducto);
        setEditando(false);
      } else {
        await axios.post(API_URL, nuevoProducto);
      }
      setNuevoProducto({ productoID: "", nombre: "", precio: "", stock: "" });
      obtenerProductos();
    } catch (error) {
      console.error("Error al guardar producto:", error);
    }
  };

  // 🔹 Editar producto
  const editarProducto = (producto) => {
    setNuevoProducto(producto);
    setEditando(true);
  };

  // 🔹 Eliminar producto
  const eliminarProducto = async (ProductoID) => {
    try {
      await axios.delete(`${API_URL}/${ProductoID}`);
      obtenerProductos();
    } catch (error) {
      console.error("Error al eliminar producto:", error);
    }
  };

  return (
    <div className="container mt-5">
      <div className="card shadow-lg border-0 rounded-4">
        <div className="card-header bg-primary text-white text-center">
          <h2 className="mb-0">{editando ? "Editar Producto" : "Agregar Producto"}</h2>
        </div>

        <div className="card-body">
          <form onSubmit={handleSubmit} className="row g-3">
            <div className="col-md-4">
              <label className="form-label">Nombre</label>
              <input
                type="text"
                name="nombre"
                value={nuevoProducto.nombre}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">Precio</label>
              <input
                type="number"
                name="precio"
                value={nuevoProducto.precio}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">Stock</label>
              <input
                type="number"
                name="stock"
                value={nuevoProducto.stock}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-12 text-center">
              <button type="submit" className={`btn ${editando ? "btn-warning" : "btn-success"} px-5`}>
                {editando ? "Actualizar" : "Agregar"}
              </button>
            </div>
          </form>
        </div>
      </div>

      <div className="card mt-5 shadow-sm border-0 rounded-4">
        <div className="card-header bg-secondary text-white text-center">
          <h3 className="mb-0">Lista de Productos</h3>
        </div>

        <div className="card-body">
          {productos.length === 0 ? (
            <p className="text-center text-muted">No hay productos registrados.</p>
          ) : (
            <div className="table-responsive">
              <table className="table table-striped table-hover align-middle text-center">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Nombre</th>
                    <th>Precio</th>
                    <th>Stock</th>
                    <th>Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {productos.map((p) => (
                    <tr key={p.ProductoID}>
                      <td>{p.productoID}</td>
                      <td>{p.nombre}</td>
                      <td>${p.precio}</td>
                      <td>{p.stock}</td>
                      <td>
                        <button
                          className="btn btn-warning btn-sm me-2"
                          onClick={() => editarProducto(p)}
                        >
                          Editar
                        </button>
                        <button
                          className="btn btn-danger btn-sm"
                          onClick={() => eliminarProducto(p.ProductoID)}
                        >
                          Eliminar
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
